export type ScheduledTask = () => void | Promise<void>;

export type SchedulerLogger = Pick<Console, "error" | "log">;

export interface SchedulerOptions {
  intervalMs: number;
  logger?: SchedulerLogger;
  name: string;
  runOnStart?: boolean;
  task: ScheduledTask;
}

export interface SchedulerHandle {
  isRunning(): boolean;
  start(): void;
  stop(): Promise<void>;
}

function validateInterval(intervalMs: number): void {
  if (!Number.isInteger(intervalMs) || intervalMs < 1) {
    throw new Error("Scheduler interval must be a positive integer.");
  }
}

export function createScheduler({
  intervalMs,
  logger = console,
  name,
  runOnStart = true,
  task,
}: SchedulerOptions): SchedulerHandle {
  validateInterval(intervalMs);

  let active = false;
  let pendingRun: Promise<void> | undefined;
  let timeoutId: NodeJS.Timeout | undefined;

  const clearScheduledRun = () => {
    if (!timeoutId) {
      return;
    }

    clearTimeout(timeoutId);
    timeoutId = undefined;
  };

  const scheduleNextRun = () => {
    if (!active) {
      return;
    }

    timeoutId = setTimeout(() => {
      timeoutId = undefined;
      pendingRun = executeRun();
    }, intervalMs);
  };

  const executeRun = async () => {
    const startedAt = Date.now();

    logger.log(`[scheduler:${name}] run started`);

    try {
      await task();
      logger.log(
        `[scheduler:${name}] run completed in ${Date.now() - startedAt}ms`,
      );
    } catch (error) {
      logger.error(`[scheduler:${name}] run failed`, error);
    } finally {
      pendingRun = undefined;
      scheduleNextRun();
    }
  };

  return {
    isRunning() {
      return active;
    },

    start() {
      if (active) {
        return;
      }

      active = true;

      if (runOnStart) {
        pendingRun = executeRun();
        return;
      }

      scheduleNextRun();
    },

    async stop() {
      if (!active) {
        return;
      }

      active = false;
      clearScheduledRun();

      await pendingRun;
    },
  };
}

