import "dotenv/config";

import { pathToFileURL } from "node:url";

import { closeDatabasePool, verifyDatabaseConnection } from "../lib/db";
import { createScheduler, type SchedulerHandle } from "../lib/scheduler";

const DEFAULT_WORKER_INTERVAL_MS = 60_000;
const WORKER_NAME = "scheduled-publishing";

function getWorkerIntervalMs(): number {
  const configuredValue =
    process.env.WORKER_INTERVAL_MS ?? `${DEFAULT_WORKER_INTERVAL_MS}`;
  const intervalMs = Number.parseInt(configuredValue, 10);

  if (Number.isNaN(intervalMs) || intervalMs < 1) {
    throw new Error("WORKER_INTERVAL_MS must be a positive integer.");
  }

  return intervalMs;
}

function runHeartbeat(): void {
  console.log(
    `[worker:${WORKER_NAME}] heartbeat ${new Date().toISOString()}`,
  );
}

function registerShutdownHandlers(scheduler: SchedulerHandle): void {
  let isShuttingDown = false;

  const shutdown = async (signal: NodeJS.Signals) => {
    if (isShuttingDown) {
      return;
    }

    isShuttingDown = true;
    console.log(`[worker:${WORKER_NAME}] received ${signal}, shutting down`);

    try {
      await scheduler.stop();
      await closeDatabasePool();
      console.log(`[worker:${WORKER_NAME}] shutdown complete`);
    } catch (error) {
      console.error(`[worker:${WORKER_NAME}] shutdown failed`, error);
      process.exitCode = 1;
    } finally {
      process.exit();
    }
  };

  process.once("SIGINT", () => {
    void shutdown("SIGINT");
  });

  process.once("SIGTERM", () => {
    void shutdown("SIGTERM");
  });
}

export async function startWorker(): Promise<SchedulerHandle> {
  const intervalMs = getWorkerIntervalMs();

  await verifyDatabaseConnection();
  console.log(`[worker:${WORKER_NAME}] database connection verified`);

  const scheduler = createScheduler({
    intervalMs,
    name: WORKER_NAME,
    task: runHeartbeat,
  });

  registerShutdownHandlers(scheduler);
  scheduler.start();

  console.log(
    `[worker:${WORKER_NAME}] started with interval ${intervalMs}ms`,
  );

  return scheduler;
}

function isDirectRun(): boolean {
  const entrypoint = process.argv[1];

  return (
    Boolean(entrypoint) && import.meta.url === pathToFileURL(entrypoint).href
  );
}

async function main(): Promise<void> {
  await startWorker();
}

if (isDirectRun()) {
  void main().catch(async (error) => {
    console.error(`[worker:${WORKER_NAME}] failed to start`, error);

    try {
      await closeDatabasePool();
    } finally {
      process.exit(1);
    }
  });
}

