    DEFAULT_WORKER_INTERVAL_MS,
    "REMINDER_JOB_INTERVAL_MS or WORKER_INTERVAL_MS",
  );
}

function getReminderJobMaxRetries(): number {
  return parseNonNegativeInteger(
    process.env.REMINDER_JOB_MAX_RETRIES ?? process.env.WORKER_MAX_RETRIES,
    DEFAULT_WORKER_MAX_RETRIES,
    "REMINDER_JOB_MAX_RETRIES or WORKER_MAX_RETRIES",
  );
}

async function runReminderAutomationJob() {
  const result = await generateReminders();

  return {
    candidateCount: result.candidateCount,
    existingCount: result.existingCount,
    filteredCount: result.filteredCount,
    generatedCount: result.generatedCount,
    dueSoonTodoCount: result.dueSoonTodoCount,
    referenceDate: result.referenceDate,
    timingDays: result.timingDays,
  };
}

function registerShutdownHandlers(scheduler: SchedulerHandle): void {
  let isShuttingDown = false;

  const shutdown = async (signal: NodeJS.Signals) => {
    if (isShuttingDown) {
      return;
    }

    isShuttingDown = true;
    writeWorkerLog("log", "shutdown.started", { signal });

    try {
      await scheduler.stop();
      await closeDatabasePool();
      writeWorkerLog("log", "shutdown.completed", { signal });
    } catch (error) {
      writeWorkerLog("error", "shutdown.failed", {
        error: error instanceof Error ? error.message : String(error),
        signal,
      });
      process.exitCode = 1;
    } finally {
      process.exit();
    }
  };

  process.once("SIGINT", () => {
    void shutdown("SIGINT");
  });

  process.once("SIGTERM", () => {
    void shutdown("SIGTERM");
  });
}

export async function startWorker(): Promise<SchedulerHandle> {
  const intervalMs = getReminderJobIntervalMs();
  const maxRetries = getReminderJobMaxRetries();

  await verifyDatabaseConnection();
  writeWorkerLog("log", "database.verified");

  const scheduler = createScheduler({
    intervalMs,
    maxRetries,
    name: REMINDER_JOB_NAME,
    task: runReminderAutomationJob,
  });

  registerShutdownHandlers(scheduler);
  scheduler.start();

  writeWorkerLog("log", "started", {
    intervalMs,
    job: REMINDER_JOB_NAME,
    maxRetries,
  });

  return scheduler;
}

function isDirectRun(): boolean {
  const entrypoint = process.argv[1];

  return (
    Boolean(entrypoint) && import.meta.url === pathToFileURL(entrypoint).href
  );
}

async function main(): Promise<void> {
  await startWorker();
}

if (isDirectRun()) {
  void main().catch(async (error) => {
    writeWorkerLog("error", "startup.failed", {
      error: error instanceof Error ? error.message : String(error),
      job: REMINDER_JOB_NAME,
    });

    try {
      await closeDatabasePool();
    } finally {
      process.exit(1);
    }
  });
}

